export async function planner(input: PerceptionInput, _context: AgentContext): Promise<ActionPlan> {
  const userMessages = input.messages
    .filter(m => m.role === 'user')
    .map(m => m.content)
    .join('\n');

  const imageNote = input.hasImages
    ? '\n[IMPORTANTE: El usuario adjuntó una captura de pantalla. Ejecuta visionTool primero.]'
    : '';

  const userPrompt = `Problema del usuario:\n${userMessages}${imageNote}\n\nHistorial de intentos: ${input.attemptCount}`;

  logger.info(`Planner: calling ${config.ollama.model.planner}`);

  let lastError = '';

  for (let attempt = 0; attempt < 2; attempt++) {
    try {
      const systemContent = attempt === 0
        ? SYSTEM_PROMPT
        : `${SYSTEM_PROMPT}\n\nTu respuesta anterior no fue válida. Error: ${lastError}\nAsegúrate de responder con JSON válido.`;

      const raw = await ollama.chat({
        model: config.ollama.model.planner,
        messages: [
          { role: 'system', content: systemContent },
          { role: 'user', content: userPrompt },
        ],
        format: 'json',
      });

      const parsed = JSON.parse(raw) as Partial<ActionPlan>;

      if (!parsed.tools || !Array.isArray(parsed.tools)) {
        throw new Error('tools no es un array');
      }

      for (const t of parsed.tools) {
        if (!t.name || !t.params) {
          throw new Error(`tool inválida: ${JSON.stringify(t)}`);
        }
      }

      return {
        reasoning: parsed.reasoning ?? '',
        tools: parsed.tools,
        verificationCriteria: parsed.verificationCriteria ?? [],
        requiresImageAnalysis: parsed.requiresImageAnalysis ?? false,
        requiresWebSearch: parsed.requiresWebSearch ?? false,
      };
    } catch (err) {
      lastError = err instanceof Error ? err.message : String(err);
      logger.warn(`Planner attempt ${attempt + 1} failed: ${lastError}`);
    }
  }

  return {
    reasoning: 'Fallback: el planificador no pudo generar un plan. Se envía mensaje genérico.',
    tools: [
      {
        name: 'sendMessage',
        params: {
          message:
            'No pude identificar tu problema. ¿Podrías describirlo con más detalle? ' +
            'Si el problema persiste, contacta a mesadeayuda@salud-digna.org.',
        },
      },
    ],
    verificationCriteria: ['Mensaje de error enviado al usuario'],
    requiresImageAnalysis: false,
    requiresWebSearch: false,
  };
}

